"""Stub for fairseq.modules.grad_multiply.GradMultiply.

Pickle references this class by name. It's a gradient-scaling helper
in real fairseq; for inference (which is all extract_feature_print.py
does) the class is never actually invoked, only its name is looked up.
"""


class GradMultiply:
    def __init__(self, *args, **kwargs):
        pass

    def __setstate__(self, state):
        if isinstance(state, dict):
            self.__dict__.update(state)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __reduce__(self):
        return (self.__class__, ())
